import Vue from "vue";
import store from "@/store/store";
import vuetify from "@/plugins/vuetify";
import ManageBreakdancePostTypes from "./ManageBreakdancePostTypes.vue";
import permission from "@/lib/permissions/directive";
import {
  BdoxTranslationPlugin,
  getTranslations
} from "@/lib/bdox-translations/bdox-translations";
import { i18nMixin } from "@/util/mixins";

Vue.directive("permission", permission);
Vue.config.productionTip = false;

// WP ensures this page is only accessible through the registered post types
const postType = new URLSearchParams(window.parent.location.search).get("page");

Vue.use(BdoxTranslationPlugin, { getTranslations });

Vue.mixin(i18nMixin);

new Vue({
  store,
  // @ts-ignore
  vuetify,
  render: h =>
    h(ManageBreakdancePostTypes, {
      props: {
        postType
      }
    })
}).$mount("#manage-templates-wrapper");
